   212→	async bulkInsert({
   213→		pairs,
   214→	}: {
   215→		pairs: {
   216→			styleIdA: number;
   217→			styleIdB: number;
   218→			copurchaseCount: number;
   219→		}[];
   220→	}): Promise<void> {
   221→		try {
   222→			const dataToInsert = pairs.map((pair) => {
   223→				const minId = Math.min(pair.styleIdA, pair.styleIdB);
   224→				const maxId = Math.max(pair.styleIdA, pair.styleIdB);
   225→
   226→				return {
   227→					_id: randomUUID(),
   228→					style_id_a: minId,
   229→					style_id_b: maxId,
   230→					copurchase_count: pair.copurchaseCount,
   231→					created_at: this.knexWrite.fn.now(),
   232→					updated_at: this.knexWrite.fn.now(),
   233→					deleted_at: null,
   234→				};
   235→			});
   236→
   237→			const batchSize = 1000;
   238→			for (let i = 0; i < dataToInsert.length; i += batchSize) {
   239→				const batch = dataToInsert.slice(i, i + batchSize);
   240→
   241→				await this.knexWrite(this.tableName).insert(batch);
   242→
   243→				this.logger.debug(
   244→					`Processed batch ${Math.floor(i / batchSize) + 1}/${Math.ceil(dataToInsert.length / batchSize)} (${batch.length} records)`,
   245→				);
   246→			}
   247→
   248→			this.logger.log(`Successfully inserted ${pairs.length} style copurchases`);
   249→		} catch (error: unknown) {
   250→			const err = error instanceof Error ? error : new Error(String(error));
   251→			this.logger.error(`Failed to bulk insert style copurchases: ${err.message}`);
   252→			throw err;
   253→		}
   254→	}
   255→
   256→	async clearExistingData(): Promise<void> {
   257→		try {
   258→			await this.knexWrite.raw(`TRUNCATE TABLE \`${this.tableName}\``);
   259→			this.logger.log('Truncated style_copurchases table');
   260→		} catch (error: unknown) {
   261→			const err = error instanceof Error ? error : new Error(String(error));
   262→			this.logger.error(`Failed to truncate style copurchases: ${err.message}`);
   263→			throw err;
   264→		}
   265→	}
   266→
   267→	async getRecordCount(): Promise<number> {
   268→		try {
   269→			const result = await this.knexRead(this.tableName)
   270→				.whereNull('deleted_at')
   271→				.count('_id as count')
   272→				.first();
   273→
   274→			return Number(result?.['count'] ?? 0);
   275→		} catch (error: unknown) {
   276→			const err = error instanceof Error ? error : new Error(String(error));
   277→			this.logger.error(
   278→				`Failed to get record count for style copurchases: ${err.message}`,
   279→			);
   280→			throw err;
   281→		}
   282→	}
   283→
   284→	private formatValidationErrors({ errors }: { errors: ValidationError[] }): string {
   285→		return errors
   286→			.map(
   287→				(error) =>
   288→					`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
   289→			)
   290→			.join('; ');
   291→	}
   292→}
