    71→		let fallbackUsed = false;
    72→
    73→		this.logger.log('[getFrequentlyBoughtTogether] Starting FBT fetch', {
    74→			styleIds,
    75→			excludeCount: exclude.length,
    76→		});
    77→
    78→		try {
    79→			const styles = await Promise.all(
    80→				styleIds.map((id) => this.stylesService.getStyleById({ styleId: id })),
    81→			);
    82→
    83→			const validStyles = styles.filter(Boolean) as IStyleBase[];
