    88→			}
    89→
    90→			this.logger.log('[getFrequentlyBoughtTogether] Valid styles found', {
    91→				validCount: validStyles.length,
    92→				inputCount: styleIds.length,
    93→			});
    94→
    95→			const cartCategoryIds = validStyles
    96→				.map((_style) => _style.primary_category_id)
    97→				.filter((id): id is number => id !== null && id !== undefined);
    98→			let correlatedCategoryIds: number[] = [];
    99→
   100→			for (const style of validStyles) {
   101→				if (style.primary_category_id) {
   102→					const correlations =
   103→						await this.categoryCorrelationsService.getTopCorrelatedCategories({
   104→							primaryCategoryId: style.primary_category_id,
   105→							limit: 4,
   106→							exclude: cartCategoryIds,
   107→						});
   108→
   109→					correlatedCategoryIds.push(...correlations.map((corr) => corr.edge_id));
   110→				}
   111→			}
   112→
   113→			correlatedCategoryIds = [...new Set(correlatedCategoryIds)];
   114→			this.logger.debug('Found correlated categories', {
   115→				count: correlatedCategoryIds.length,
   116→				styleIds,
   117→			});
   118→
   119→			if (correlatedCategoryIds.length === 0) {
   120→				this.logger.warn('No correlations found, using fallback', { styleIds });
   121→				correlatedCategoryIds = await this.stylesService.getMostPopularCategories({
   122→					limit: 4,
   123→				});
   124→				fallbackUsed = true;
   125→			}
